package org.apache.commons.cli;

import java.util.ArrayList;
import java.util.List;

/**
 * The class GnuParser provides an implementation of the
 * {@link Parser#flatten(Options,String[],boolean) flatten} method.
 *
 * @author John Keyes (john at integralsource.com)
 * @see Parser
 * @version $Revision$
 */
public class GnuParser extends Parser {

    /**
     * <p>This flatten method does so using the following rules:
     * <ol>
     *  <li>If an {@link Option} exists for the first character of
     *  the <code>arguments</code> entry <b>AND</b> an {@link Option}
     *  does not exist for the whole <code>argument</code> then
     *  add the first character as an option to the processed tokens
     *  list e.g. "-D" and add the rest of the entry to the also.</li>
     *  <li>Otherwise just add the token to the processed tokens list.
     *  </li>
     * </ol>
     * </p>
     *
     * @param options The Options to parse the arguments by.
     * @param arguments The arguments that have to be flattened.
     * @param stopAtNonOption specifies whether to stop
     * flattening when a non option has been encountered
     * @return a String array of the flattened arguments
     */
    protected String[] flatten(Options options, String[] arguments, boolean stopAtNonOption)
    {
        List tokens = new ArrayList();

        boolean eatTheRest = false;

        for (int i = 0; i < arguments.length; i++)
        {
            String arg = arguments[i];

            if ("--".equals(arg))
            {
                eatTheRest = true;
                tokens.add("--");
            }
            else if ("-".equals(arg))
            {
                tokens.add("-");
            }
            else if (arg.startsWith("-"))
            {
                String opt = Util.stripLeadingHyphens(arg);

                if (options.hasOption(opt))
                {
                    tokens.add(arg);
                }
                else
                {
                    // Look for an '=' to separate option from value
                    int pos = arg.indexOf('=');
                    if (pos != -1)
                    {
                        // Check if the part before '=' is a valid option (for cases like -foo=bar where foo is a long option)
                        String optBeforeEquals = arg.substring(0, pos);
                        String valueAfterEquals = arg.substring(pos + 1);

                        if (options.hasOption(optBeforeEquals))
                        {
                            // The part before '=' is a valid option (likely long option), treat as complete option=value
                            tokens.add(optBeforeEquals);
                            tokens.add(valueAfterEquals);
                        }
                        else
                        {
                            // The first 2 chars form a valid option, but it might be short option with =value
                            if (options.hasOption(arg.substring(0, 2)))
                            {
                                tokens.add(arg.substring(0, 2)); // -f
                                tokens.add(arg.substring(2)); // =bar (still includes =, but parser will handle this)
                            }
                            else
                            {
                                eatTheRest = stopAtNonOption;
                                tokens.add(arg);
                            }
                        }
                    }
                    else
                    {
                        // No '=' found, use the original logic
                        if (options.hasOption(arg.substring(0, 2)))
                        {
                            tokens.add(arg.substring(0, 2)); // -D
                            tokens.add(arg.substring(2)); // property=value
                        }
                        else
                        {
                            eatTheRest = stopAtNonOption;
                            tokens.add(arg);
                        }
                    }
                    else
                    {
                        eatTheRest = stopAtNonOption;
                        tokens.add(arg);
                    }
                }
            }
            else
            {
                tokens.add(arg);
            }

            if (eatTheRest)
            {
                for (i++; i < arguments.length; i++)
                {
                    tokens.add(arguments[i]);
                }
            }
        }

        return (String[]) tokens.toArray(new String[tokens.size()]);
    }
}

